+      setSize({
+        columns: process.stdout.columns ?? size.columns,
+        rows: process.stdout.rows ?? size.rows,
+      });
+    };
+    process.stdout.on('resize', handler);
+    return () => {
+      process.stdout.off('resize', handler);
+    };
+    // eslint-disable-next-line react-hooks/exhaustive-deps
+  }, []);
+
+  return size;
